import{_ as d,o as e,c as a,a2 as r}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"إعدادات الصفحة","description":"","frontmatter":{},"headers":[],"relativePath":"ar-SA/Page/page-settings.md","filePath":"ar-SA/Page/page-settings.md","lastUpdated":1781962217000}'),o={name:"ar-SA/Page/page-settings.md"};function n(i,t,l,c,h,s){return e(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="إعدادات-الصفحة" tabindex="-1">إعدادات الصفحة <a class="header-anchor" href="#إعدادات-الصفحة" aria-label="Permalink to &quot;إعدادات الصفحة&quot;">​</a></h1><p>تتحكم Page settings في مظهر الموقع، والقيم الافتراضية لصفحة الرفع، وصور الخلفية، ومظهر لوحة الإدارة.</p><h2 id="global-settings" tabindex="-1">Global Settings <a class="header-anchor" href="#global-settings" aria-label="Permalink to &quot;Global Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>الخيار</th><th>الغرض</th></tr></thead><tbody><tr><td>Site title</td><td>العنوان الظاهر في تبويب المتصفح.</td></tr><tr><td>Site icon</td><td>الأيقونة الصغيرة الظاهرة في تبويب المتصفح.</td></tr><tr><td>ImgBed name</td><td>الاسم الظاهر في صفحات الواجهة الأمامية.</td></tr><tr><td>ImgBed logo</td><td>صورة الشعار الظاهرة في صفحات الواجهة الأمامية.</td></tr><tr><td>Logo link</td><td>الرابط الذي يفتح عند الضغط على الشعار أو الصورة الرمزية.</td></tr><tr><td>Background switch interval</td><td>فترة تدوير عدة خلفيات بالميلي ثانية. <code>60000</code> تعني 60 ثانية.</td></tr><tr><td>Background opacity</td><td>شفافية صورة الخلفية من <code>0</code> إلى <code>1</code>. القيم الأقل تجعلها أخف.</td></tr><tr><td>Default URL prefix</td><td>prefix المستخدم عند إنشاء روابط الصور. الفارغ يعني استخدام نطاق الموقع الحالي.</td></tr></tbody></table><h2 id="client-settings" tabindex="-1">Client Settings <a class="header-anchor" href="#client-settings" aria-label="Permalink to &quot;Client Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>الخيار</th><th>الغرض</th></tr></thead><tbody><tr><td>Announcement</td><td>إعلان يظهر أعلى صفحة الرفع. يدعم HTML.</td></tr><tr><td>Default upload channel</td><td>قناة الرفع المختارة افتراضيًا في صفحة الرفع. يمكن أيضًا اختيار Smart Dispatch.</td></tr><tr><td>Default upload directory</td><td>مجلد الرفع الافتراضي، مثل <code>/user/</code>. الفارغ أو <code>/</code> يعني الجذر.</td></tr><tr><td>Default naming method</td><td>طريقة إنشاء اسم الملف افتراضيًا بعد الرفع. انظر أدناه.</td></tr><tr><td>Convert to WebP by default</td><td>يحوّل الصور إلى WebP قبل الرفع.</td></tr><tr><td>Enable compression by default</td><td>يضغط الصور محليًا في المتصفح قبل الرفع.</td></tr><tr><td>Default compression threshold</td><td>يبدأ الضغط تلقائيًا عندما تتجاوز الصورة هذا الحجم بالـ MB.</td></tr><tr><td>Default target size</td><td>الحجم المستهدف بعد الضغط بالـ MB.</td></tr><tr><td>Login page background</td><td>خلفية صفحة دخول المستخدم.</td></tr><tr><td>Upload page background</td><td>خلفية صفحة الرفع.</td></tr><tr><td>Footer portal link</td><td>الرابط الذي يفتحه زر footer portal.</td></tr><tr><td>Hide footer</td><td>يخفي تذييل الواجهة الأمامية عند تفعيله.</td></tr></tbody></table><h2 id="admin-settings" tabindex="-1">Admin Settings <a class="header-anchor" href="#admin-settings" aria-label="Permalink to &quot;Admin Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>الخيار</th><th>الغرض</th></tr></thead><tbody><tr><td>Admin login background</td><td>خلفية صفحة دخول الإدارة.</td></tr><tr><td>Admin background</td><td>خلفية صفحات الإدارة. يمكن استخدام رابط صورة واحد أو عدة روابط.</td></tr><tr><td>Image loading mode</td><td>وضع تحميل المعاينات في قائمة ملفات الإدارة. Original يحمّل الصور الأصلية. Smart loading يفضل thumbnails للصور العامة و originals للصور المقيدة.</td></tr><tr><td>Thumbnail source</td><td>خدمة إنشاء thumbnails: wsrv.nl أو Cloudflare Image Resizing أو WordPress Photon. يجب تفعيل Cloudflare Image Resizing في Cloudflare قبل اختياره.</td></tr><tr><td>Live2D widget</td><td>يعرض شخصية Live2D في لوحة الإدارة.</td></tr><tr><td>Firework click effect</td><td>يعرض تأثير ألعاب نارية عند الضغط على الصفحة.</td></tr><tr><td>Star cursor trail</td><td>يعرض أثر نجوم عند تحريك الفأرة.</td></tr></tbody></table><h2 id="صيغ-صور-الخلفية" tabindex="-1">صيغ صور الخلفية <a class="header-anchor" href="#صيغ-صور-الخلفية" aria-label="Permalink to &quot;صيغ صور الخلفية&quot;">​</a></h2><p>تدعم Login page background و upload page background و admin login background هذه الصيغ:</p><table tabindex="0"><thead><tr><th>القيمة</th><th>التأثير</th></tr></thead><tbody><tr><td><code>bing</code></td><td>يستخدم تدوير خلفيات Bing.</td></tr><tr><td><code>[&quot;https://example.com/1.jpg&quot;,&quot;https://example.com/2.jpg&quot;]</code></td><td>يدوّر عدة صور.</td></tr><tr><td><code>[&quot;https://example.com/1.jpg&quot;]</code></td><td>يستخدم صورة خلفية واحدة.</td></tr><tr><td><code>[&quot;https://your-domain.com/random?...&quot;]</code></td><td>يستخدم رابط random image API. يمكنك ضبط Random Image API الخاص بك في Other Settings ثم لصق الرابط الناتج هنا كخلفية واحدة.</td></tr></tbody></table><p>يدعم admin background روابط الصور. يمكن فصل عدة روابط بفواصل إنجليزية كما توضح الصفحة. القيمة الفارغة تعني استخدام الخلفية الافتراضية.</p><h2 id="default-naming-method" tabindex="-1">Default Naming Method <a class="header-anchor" href="#default-naming-method" aria-label="Permalink to &quot;Default Naming Method&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Result</th></tr></thead><tbody><tr><td>Default</td><td>Time-random prefix + original filename، مثل <code>1760000000000_cat.png</code>.</td></tr><tr><td>Prefix only</td><td>Time-random prefix والامتداد فقط، مثل <code>1760000000000.png</code>.</td></tr><tr><td>Original name only</td><td>يحافظ على original filename، مثل <code>cat.png</code>. عند التكرار يضيف ImgBed <code>(1)</code> و <code>(2)</code> وهكذا.</td></tr><tr><td>Short link</td><td>يستخدم short ID من 8 أحرف مع الامتداد، مثل <code>a1b2c3d4.png</code>.</td></tr></tbody></table>',14)])])}const u=d(o,[["render",n]]);export{m as __pageData,u as default};
